export interface DailyChallengeQuestion {
  day: number;
  question: string;
  options: string[];
  correctIndex: number;
  explanation: string;
  category: string;
  difficulty: "easy" | "medium" | "hard";
  xpReward: number;
}

// Helper to generate the full 365-day question bank
const q = (
  day: number,
  question: string,
  options: string[],
  correctIndex: number,
  explanation: string,
  category: string,
  difficulty: "easy" | "medium" | "hard" = "medium",
  xpReward?: number
): DailyChallengeQuestion => ({
  day,
  question,
  options,
  correctIndex,
  explanation,
  category,
  difficulty,
  xpReward: xpReward ?? (difficulty === "easy" ? 15 : difficulty === "medium" ? 25 : 40),
});

