/** Get the challenge for today based on a day-of-year calculation */
export function getTodaysChallengeDay(): number {
  const now = new Date();
  const start = new Date(now.getFullYear(), 0, 0);
  const diff = now.getTime() - start.getTime();
  const oneDay = 1000 * 60 * 60 * 24;
  const dayOfYear = Math.floor(diff / oneDay); // 1-365/366
  return ((dayOfYear - 1) % 365) + 1; // Wrap to 1-365
}

export function getTodaysChallenge(): DailyChallengeQuestion {
  const day = getTodaysChallengeDay();
  return DAILY_CHALLENGE_QUESTIONS.find(q => q.day === day) || DAILY_CHALLENGE_QUESTIONS[0];
}

/** Milliseconds until midnight */
export function getTimeUntilMidnight(): number {
  const now = new Date();
  const midnight = new Date(now);
  midnight.setHours(24, 0, 0, 0);
  return midnight.getTime() - now.getTime();
}
